INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (44, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", 16, 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ", 155, 2, "A", 0, 8, 100101, "人助け、応援", "獣人族", "東山奈央");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (47, "トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", 17, 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ", 158, 2, "O", 0, 4, 100201, "料理、人間観察", "ヒューマン", "種田梨沙");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (46, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", 18, 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ", 163, 2, "B", 0, 1, 100301, "読書、乗馬、お茶", "魔族", "早見沙織");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (27, "リトルリリカル", "探検好きのイタズラっ子", 9, 10, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "ミソギ", 128, 5, "O", 0, 8, 100401, "いたずら、探検", "ヒューマン", "諸星すみれ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (40, "王宮騎士団（NIGHTMARE）", "ヒーローに憧れる騎士見習いの少女", 12, 25, "？？？", "マツリ", 146, 8, "O", 0, 11, 100501, "ヒーローごっこ", "獣人族", "下田麻美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (42, "悪魔偽王国軍（ディアボロス）", "甘え上手なみんなの人気者", 13, 22, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "アカリ", 150, 7, "O", 0, 11, 100601, "サックス", "魔族", "浅倉杏美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (32, "悪魔偽王国軍（ディアボロス）", "プリン大好きゴースト娘", 14, 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "ミヤコ", 130, 7, "B", 0, 1, 100701, "プリンを食べること", "魔族", "雨宮天");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (40, "ヴァイスフリューゲル　ランドソル支部", "ボクは誰よりも美しい", 14, 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ユキ", 150, 15, "AB", 0, 10, 100801, "鏡で自分を見ること", "エルフ", "大空直美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (45, "トワイライトキャラバン", "前世を信じる中二病患者、「疾風の冥姫」", 17, 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "アンナ", 159, 13, "A", 0, 7, 100901, "小説執筆", "魔族", "髙野麻美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (42, "自警団（カォン）", "マホマホ王国のプリンセス", 16, 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホ", 155, 10, "O", 0, 9, 101001, "空想、ぬいぐるみ集め", "獣人族", "内田真礼");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (44, "ラビリンス", "人懐っこくてマシンガントークな妹系少女", 15, 25, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "リノ", 156, 3, "A", 0, 8, 101101, "お裁縫", "ヒューマン", "阿澄佳奈");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (46, "フォレスティエ", "みんなのために超能力を使う眠り姫", 17, 24, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "ハツネ", 156, 6, "A", 0, 12, 101201, "妹と遊ぶこと、二度寝、昼寝、早寝", "エルフ", "大橋彩香");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (55, "トワイライトキャラバン", "オタク全開な魔法少女", 18, 21, "", "ナナカ", 166, 13, "O", 0, 8, 101301, "読書、魔法", "魔族", "佳村はるか");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (41, "自警団（カォン）", "頭脳明晰な美少女名探偵", 15, 3, "test", "カスミ", 152, 10, "AB", 0, 11, 101401, "読書、推理", "獣人族", "水瀬いのり");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (54, "フォレスティエ", "母性溢れる優しいみんなの「ミサト先生」", 21, 5, "test", "ミサト", 165, 6, "O", 0, 9, 101501, "絵本作り", "エルフ", "國府田マリ子");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (48, "ルーセント学院", "天真爛漫で人気者のカリスマモデル", 17, 10, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "スズナ", 167, 14, "O", 0, 4, 101601, "ファッション", "魔族", "上坂すみれ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (53, "自警団（カォン）", "いつでも「なんくるないさ～」な天然娘", 17, 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "カオリ", 158, 10, "A", 0, 7, 101701, "踊り、空手", "獣人族", "高森奈津美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (52, "ルーセント学院", "多くの男性を魅了する無垢な女教師", 23, 14, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "イオ", 162, 14, "B", 0, 8, 101801, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "魔族", "伊藤静");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (21, "リトルリリカル", "お歌もにんじんも、ウサギさんも大好き♪", 10, 3, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "ミミ", 117, 5, "O", 0, 4, 102001, "かわいいもの集め", "獣人族", "日高里菜");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (40, "サレンディア救護院", "泣き虫で臆病な守ってあげたい女の子", 12, 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "クルミ", 150, 9, "B", 0, 6, 102101, "観劇、おままごと", "ヒューマン", "植田佳奈");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (40, "悪魔偽王国軍（ディアボロス）", "人見知りであまのじゃくな女の子", 13, 22, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "ヨリ", 150, 7, "O", 0, 11, 102201, "ゲーム全般", "魔族", "原紗友里");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (38, "サレンディア救護院", "ぷうきちといつも一緒！", 14, 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "アヤネ", 148, 9, "B", 0, 5, 102301, "屋内でできる遊び", "ヒューマン", "芹澤優");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (43, "サレンディア救護院", "お嬢さまのためにがんばるドジっ娘メイド", 15, 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "スズメ", 154, 9, "O", 0, 12, 102501, "ご奉仕", "ヒューマン", "悠木碧");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (42, "牧場（エリザベスパーク）", "遊びと睡眠が何より大事なぐうたら娘", 17, 1, "test", "リン", 144, 11, "B", 0, 1, 102601, "あんパン", "獣人族", "小岩井ことり");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (43, "トワイライトキャラバン", "運命の相手に一途すぎる乙女", 16, 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ", 154, 13, "B", 0, 7, 102701, "実験、裁縫、料理", "魔族", "橋本ちなみ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (43, "サレンディア救護院", "救護院を経営する優しい庶民派お嬢様", 17, 4, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレン", 156, 9, "A", 0, 10, 102801, "経営、お茶会", "エルフ", "堀江由衣");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (40, "カルミナ", "歌って踊れる大人気アイドル", 17, 24, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "ノゾミ", 157, 4, "B", 0, 1, 102901, "舞台鑑賞、ダンス", "ヒューマン", "日笠陽子");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (51, "ヴァイスフリューゲル　ランドソル支部", "トーゴクの神秘、オシエテクダサイ！", 16, 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ニノン", 163, 15, "O", 0, 8, 103001, "忍法開発", "ヒューマン", "佐藤聡美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (42, "悪魔偽王国軍（ディアボロス）", "占いが得意な霊能少女", 18, 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ", 157, 7, "AB", 0, 12, 103101, "占い", "魔族", "大坪由佳");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (45, "メルクリウス財団", "一人前の商人を目指すパワフルお嬢様", 18, 12, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "アキノ", 157, 12, "AB", 0, 3, 103201, "慈善事業", "ヒューマン", "松嵜麗");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (35, "牧場（エリザベスパーク）", "みんなを笑顔にするお笑い牧場主", 20, 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "マヒル", 142, 11, "B", 0, 3, 103301, "漫才", "ヒューマン", "新田恵海");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (55, "メルクリウス財団", "純情でほっとけない大人の女性", 22, 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "ユカリ", 164, 12, "A", 0, 3, 103401, "ウインドーショッピング", "エルフ", "今井麻美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (21, "リトルリリカル", "礼儀正しくしっかり者のちびっ子優等生", 8, 2, "test", "キョウカ", 118, 5, "A", 0, 2, 103601, "お勉強", "エルフ", "小倉唯");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (43, "王宮騎士団（NIGHTMARE）", "義理堅くてからかい好きな剣術少女", 13, 11, "test", "トモ", 149, 8, "A", 0, 8, 103701, "剣術、年長者をからかう", "ヒューマン", "茅原実里");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (40, "牧場（エリザベスパーク）", "読書が趣味の病弱少女", 14, 3, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "シオリ", 153, 11, "A", 0, 11, 103801, "読書、お散歩", "獣人族", "小清水亜美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (44, "フォレスティエ", "「友達」に憧れる、エルフの森の女の子", 13, 6, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "アオイ", 158, 6, "AB", 0, 6, 104001, "友達作りのイメトレ", "エルフ", "花澤香菜");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (46, "カルミナ", "人々を守るために歌う、唱喚士の少女", 17, 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ", 163, 4, "O", 0, 6, 104201, "各種楽器", "ヒューマン", "福原綾香");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (54, "自警団（カォン）", "男勝りで情に厚いワイルド娘", 17, 9, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "マコト", 168, 10, "O", 0, 8, 104301, "お菓子作り", "獣人族", "小松未可子");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (50, "悪魔偽王国軍（ディアボロス）", "かつては夜を支配した最強の吸血鬼", "??", 5, "test", "イリヤ", 172, 7, "A", 0, 5, 104401, "世界征服", "魔族", "丹下桜");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (49, "ヴァイスフリューゲル　ランドソル支部", "妄想大好き！　ほんとは照れ屋な女の子", 18, 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ", 157, 15, "AB", 0, 11, 104501, "小説を読むこと", "ヒューマン", "長妻樹里");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (48, "メルクリウス財団", "弱きを助け強きをくじく猫娘", 19, 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ", 158, 12, "AB", 0, 3, 104601, "猫とたわむれること", "獣人族", "沼倉愛美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (50, "王宮騎士団（NIGHTMARE）", "素顔を見せない冷静沈着な女性騎士", 25, 25, "？？？", "ジュン", 171, 8, "A", 0, 10, 104701, "格闘技、湯浴み", "ヒューマン", "川澄綾子");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (49, "メルクリウス財団", "仕事も私事も効率優先な傭兵少女", 20, 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ", 163, 12, "O", 0, 11, 104801, "傭兵などのアルバイト", "ヒューマン", "田所あずさ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (54, "ラビリンス", "お姉ちゃんがお世話してあげるからねっ！", 18, 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル", 168, 3, "O", 0, 10, 104901, "家事全般", "ヒューマン", "生天目仁美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (22, "ルーセント学院", "ちょっとおませな恋に恋する女の子", 11, 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ミサキ", 120, 14, "A", 0, 1, 105001, "ファッション誌鑑賞、コスメ集め", "魔族", "久野美咲");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (53, "トワイライトキャラバン", "実験が趣味の危険な科学者", 27, 7, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "ミツキ", 166, 13, "A", 0, 3, 105101, "研究、実験", "ヒューマン", "三石琴乃");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100, "牧場（エリザベスパーク）", "乙女チックなもふもふアニマル", 17, 14, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "リマ", 150, 11, "A", 0, 3, 105201, "毛繕い、お喋り", "獣人族", "徳井青空");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (33, "ヴァイスフリューゲル　ランドソル支部", "見た目も中身もお子ちゃまな異国の軍人", 17, 28, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "モニカ", 140, 15, "A", 0, 7, 105301, "お菓子屋通い", "ヒューマン", "辻あゆみ");
