INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (45, "？？？", "空への冒険を夢見る騎空士の少女", 17, 10, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "ジータ", 156, "", "O", 0, 3, 105701, "冒険、おしゃべり", "ヒューマン", "金元寿子");
