INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (48, "メルクリウス財団", "弱きを助け強きをくじく猫娘", 19, 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ（サマー）", 158, 12, "AB", 0, 3, 107901, "猫とたわむれること", "獣人族", "沼倉愛美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (49, "メルクリウス財団", "仕事も私事も効率優先な傭兵少女", 20, 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ（サマー）", 163, 12, "O", 0, 11, 108001, "傭兵などのアルバイト", "ヒューマン", "田所あずさ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (42, "悪魔偽王国軍（ディアボロス）", "占いが得意な霊能少女", 18, 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ（ハロウィン）", 157, 7, "AB", 0, 12, 108101, "占い", "魔族", "大坪由佳");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (32, "悪魔偽王国軍（ディアボロス）", "プリン大好きゴースト娘", 14, 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "ミヤコ（ハロウィン）", 130, 7, "B", 0, 1, 108201, "プリンを食べること", "魔族", "雨宮天");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (22, "ルーセント学院", "ちょっとおませな恋に恋する女の子", 11, 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ミサキ（ハロウィン）", 120, 14, "A", 0, 1, 108301, "ファッション誌鑑賞、コスメ集め", "魔族", "久野美咲");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (46, "カルミナ", "人々を守るために歌う、唱喚士の少女", 17, 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ（クリスマス）", 163, 4, "O", 0, 6, 108401, "各種楽器", "ヒューマン", "福原綾香");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (40, "サレンディア救護院", "泣き虫で臆病な守ってあげたい女の子", 12, 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "クルミ（クリスマス）", 150, 9, "B", 0, 6, 108501, "観劇、おままごと", "ヒューマン", "植田佳奈");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (38, "サレンディア救護院", "ぷうきちといつも一緒！", 14, 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "アヤネ（クリスマス）", 148, 9, "B", 0, 5, 108601, "屋内でできる遊び", "ヒューマン", "芹澤優");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (44, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", 16, 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ（ニューイヤー）", 155, 2, "A", 0, 8, 108701, "人助け、応援", "獣人族", "東山奈央");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (47, "トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", 17, 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ（ニューイヤー）", 158, 2, "O", 0, 4, 108801, "料理、人間観察", "ヒューマン", "種田梨沙");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (46, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", 18, 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ（ニューイヤー）", 163, 2, "B", 0, 1, 108901, "読書、乗馬、お茶", "魔族", "早見沙織");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (43, "トワイライトキャラバン", "運命の相手に一途すぎる乙女", 16, 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ（バレンタイン）", 154, 13, "B", 0, 7, 109001, "実験、裁縫、料理", "魔族", "橋本ちなみ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (54, "ラビリンス", "お姉ちゃんがお世話してあげるからねっ！", 18, 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル（バレンタイン）", 168, 3, "O", 0, 10, 109101, "家事全般", "ヒューマン", "生天目仁美");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (55, "？？？", "英霊と契約を結んだマナリアの天才王女", 17, 1, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "アン", 156, "", "AB", 0, 12, 109201, "読書", "ヒューマン", "日笠陽子");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (45, "？？？", "マナリア魔法学院の新入生", 16, 4, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "ルゥ", 144, "", "O", 0, 2, 109301, "食べること、眠ること", "ヒューマン", "こやまきみこ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (67, "？？？", "人を超越した力を有す心優しい竜姫", 17, 3, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "グレア", 167, "", "B", 0, 11, 109401, "ピアノ", "半人半竜", "福原綾香");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (49, "ヴァイスフリューゲル　ランドソル支部", "妄想大好き！　ほんとは照れ屋な女の子", 18, 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ（オーエド）", 157, 15, "AB", 0, 11, 109501, "小説を読むこと", "ヒューマン", "長妻樹里");
