INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (45, "トワイライトキャラバン", "前世を信じる中二病患者、「疾風の冥姫」", 17, 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "アンナ（パイレーツ）", 159, 13, "A", 0, 7, 121901, "小説執筆", "魔族", "髙野麻美");
