INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (44, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", 16, 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ（サマー）", 155, 2, "A", 0, 8, 122401, "人助け、応援", "獣人族", "東山奈央");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (46, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", 18, 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ（サマー）", 163, 2, "B", 0, 1, 122501, "読書、乗馬、お茶", "魔族", "早見沙織");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (47, "トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", 17, 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ（サマー）", 158, 2, "O", 0, 4, 122601, "料理、人間観察", "ヒューマン", "種田梨沙");
